body:
If you use an old-style Grand Central tap to tap a port of a module which is extracted, the resulting XMR can go outside of the scope of the design under test (DUT). This creates a situation where the resultant XMR in the Data Tap external module points to something outside the DUT. If the user then tries to compile just the DUT, elaboration then fails.

Things look correct when using new-style Grand Central taps, though! (Or: dataflow always beats spooky annotations.)

I do not view this as an actual bug in Grand Central taps, Extract Instances, or in the annotations that compose these (e.g., MarkDUTAnnotation). Instead, I view this as user error arising from the strange ways that all these baroque features interact.

I.e., this is a "won't fix" right now and is "fixed" by switching to new-style taps.

To reproduce this, you can use the following circuit:

```
circuit Foo: %[[
  {
    "class": "sifive.enterprise.firrtl.ExtractClockGatesFileAnnotation",
    "filename": "ClockGates.txt"
  },
  {
    "class": "sifive.enterprise.firrtl.MarkDUTAnnotation",
    "target": "Foo|Bar"
  },
  {
    "class": "sifive.enterprise.grandcentral.DataTapsAnnotation",
    "blackBox": "~Foo|DataTap",
    "keys": [
      {
        "class": "sifive.enterprise.grandcentral.ReferenceDataTapKey",
        "source": "~Foo|Foo/bar:Bar>sub.a",
        "portName": "~Foo|DataTap>_0"
      }
    ]
  },
  {
    "class": "sifive.enterprise.grandcentral.DataTapsAnnotation",
    "keys": [
      {
        "class": "sifive.enterprise.grandcentral.ReferenceDataTapKey",
        "source": "~Foo|Foo/bar:Bar>sub.a",
        "sink": "~Foo|Bar>newTap"
      }
    ]
  }
]]
  extmodule EICG_wrapper:
    output a: UInt<1>

    defname = EICG_wrapper

  extmodule DataTap:
    output _0: UInt<1>

  module Bar:
    output a: UInt<1>

    inst sub of EICG_wrapper
    inst oldTap of DataTap

    wire newTap: UInt<1>
    newTap is invalid

    a <= xor(oldTap._0, newTap)

  module Foo:
    output a: UInt<1>

    inst bar of Bar
    a <= bar.a
```

This produces the following Verilog. `oldTap` is driven by an XMR to goes above the DUT. `newTap` is driven by the port on `Foo` that extraction creates.

```verilog
// external module EICG_wrapper

// VCS coverage exclude_file
module DataTap_impl_0(
  output _0);

  assign _0 = Foo.sub.a;
endmodule

module Bar(
  input  clock_gate_0_a,
  output a);

  wire _oldTap__0;
  wire _GEN = clock_gate_0_a;
  DataTap_impl_0 oldTap (
    ._0 (_oldTap__0)
  );
  assign a = _oldTap__0 ^ Bar._GEN;
endmodule

module Foo(
  output a);

  wire _sub_a;
  Bar bar (
    .clock_gate_0_a (_sub_a),
    .a              (a)
  );
  EICG_wrapper sub (
    .a (_sub_a)
  );
endmodule


// ----- 8< ----- FILE "ClockGates.txt" ----- 8< -----

clock_gate_0 -> Bar.sub
```
